def get_timestamp():
    """Generate a timestamp string for the backup filename."""
    return datetime.datetime.now().strftime("%Y%m%d_%H%M%S")


def get_backup_filename(directory, fmt):
    """Generate the backup filename based on directory name and format."""
    dir_basename = os.path.basename(os.path.normpath(directory))
    timestamp = get_timestamp()
    extensions = {
        'tar.gz': '.tar.gz',
        'tar.bz2': '.tar.bz2',
        'zip': '.zip',
        '7z': '.7z',
    }
    ext = extensions.get(fmt, '.tar.gz')
    return "{0}_backup_{1}{2}".format(dir_basename, timestamp, ext)


def validate_directory(directory):
    """Validate that the given directory exists and is readable."""
    if not os.path.exists(directory):
        print("Error: Directory '{0}' does not exist.".format(directory), file=sys.stderr)
        return False
    if not os.path.isdir(directory):
        print("Error: '{0}' is not a directory.".format(directory), file=sys.stderr)
        return False
    if not os.access(directory, os.R_OK):
        print("Error: Directory '{0}' is not readable.".format(directory), file=sys.stderr)
        return False
    return True


def get_directory_size(directory):
    """Calculate total size of directory in bytes."""
    total_size = 0
    for dirpath, dirnames, filenames in os.walk(directory):
        for filename in filenames:
            filepath = os.path.join(dirpath, filename)
            try:
                total_size += os.path.getsize(filepath)
            except (OSError, IOError):
                pass
    return total_size


def format_size(size_bytes):
    """Format byte size into human-readable string."""
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size_bytes < 1024.0:
            return "{0:.2f} {1}".format(size_bytes, unit)
        size_bytes /= 1024.0
    return "{0:.2f} PB".format(size_bytes)


def count_files(directory):
    """Count total files in a directory tree."""
    count = 0
    for dirpath, dirnames, filenames in os.walk(directory):
        count += len(filenames)
    return count


def create_tar_gz(directory, output_path):
    """Create a tar.gz compressed archive."""
    print("Creating tar.gz archive...")
    try:
        with tarfile.open(output_path, "w:gz") as tar:
            tar.add(directory, arcname=os.path.basename(os.path.normpath(directory)))
        return True
    except (tarfile.TarError, IOError, OSError) as e:
        print("Error creating tar.gz archive: {0}".format(e), file=sys.stderr)
        return False


def create_tar_bz2(directory, output_path):
    """Create a tar.bz2 compressed archive."""
    print("Creating tar.bz2 archive...")
    try:
        with tarfile.open(output_path, "w:bz2") as tar:
            tar.add(directory, arcname=os.path.basename(os.path.normpath(directory)))
        return True
    except (tarfile.TarError, IOError, OSError) as e:
        print("Error creating tar.bz2 archive: {0}".format(e), file=sys.stderr)
        return False


def create_zip(directory, output_path):
    """Create a zip compressed archive."""
    print("Creating zip archive...")
    try:
        dir_basename = os.path.basename(os.path.normpath(directory))
        # Try to use ZIP_DEFLATED, fall back to ZIP_STORED
        try:
            compression = zipfile.ZIP_DEFLATED
        except AttributeError:
            compression = zipfile.ZIP_STORED
            print("Warning: ZIP_DEFLATED not available, using ZIP_STORED (no compression)")

        with zipfile.ZipFile(output_path, 'w', compression) as zipf:
            for dirpath, dirnames, filenames in os.walk(directory):
                for filename in filenames:
                    filepath = os.path.join(dirpath, filename)
                    # Calculate the archive name relative to the parent of the target directory
                    relpath = os.path.relpath(filepath, os.path.dirname(os.path.normpath(directory)))
                    try:
                        zipf.write(filepath, relpath)
                    except (IOError, OSError) as e:
                        print("Warning: Could not add '{0}': {1}".format(filepath, e), file=sys.stderr)
            # Also add empty directories
            for dirpath, dirnames, filenames in os.walk(directory):
                if not filenames and not dirnames:
                    relpath = os.path.relpath(dirpath, os.path.dirname(os.path.normpath(directory)))
                    zipf.write(dirpath, relpath)
        return True
    except (zipfile.BadZipFile if hasattr(zipfile, 'BadZipFile') else zipfile.BadZipfile,
            IOError, OSError) as e:
        print("Error creating zip archive: {0}".format(e), file=sys.stderr)
        return False


def find_7z_binary():
    """Find the 7z binary on the system."""
    possible_names = ['7z', '7za', '7zr']
    possible_paths = [
        '/usr/bin', '/usr/local/bin', '/opt/local/bin',
        '/snap/bin', '/usr/lib/p7zip',
    ]

    for name in possible_names:
        # Check if it's in PATH
        for path_dir in os.environ.get('PATH', '').split(os.pathsep):
            full_path = os.path.join(path_dir, name)
            if os.path.isfile(full_path) and os.access(full_path, os.X_OK):
                return full_path

        # Check known paths
        for path_dir in possible_paths:
            full_path = os.path.join(path_dir, name)
            if os.path.isfile(full_path) and os.access(full_path, os.X_OK):
                return full_path

    return None


def create_7z(directory, output_path):
    """Create a 7z compressed archive using external 7z command."""
    print("Creating 7z archive...")

    binary = find_7z_binary()
    if binary is None:
        print("Error: 7z/7za/7zr binary not found on the system.", file=sys.stderr)
        print("Please install p7zip: apt-get install p7zip-full (Debian/Ubuntu)", file=sys.stderr)
        print("                   or: yum install p7zip p7zip-plugins (RHEL/CentOS)", file=sys.stderr)
        return False

    try:
        cmd = [binary, 'a', '-t7z', '-mx=5', output_path, directory]
        process = subprocess.Popen(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE
        )
        stdout, stderr = process.communicate()

        if process.returncode != 0:
            error_msg = stderr.decode('utf-8', errors='replace') if stderr else 'Unknown error'
            print("Error creating 7z archive (exit code {0}): {1}".format(
                process.returncode, error_msg), file=sys.stderr)
            return False
        return True
    except (OSError, IOError) as e:
        print("Error running 7z command: {0}".format(e), file=sys.stderr)
        return False


def verify_archive(output_path, fmt):
    """Verify that the created archive is valid."""
    print("Verifying archive integrity...")
    try:
        if fmt in ('tar.gz', 'tar.bz2'):
            mode = 'r:gz' if fmt == 'tar.gz' else 'r:bz2'
            with tarfile.open(output_path, mode) as tar:
                members = tar.getmembers()
                print("  Archive contains {0} entries.".format(len(members)))
            return True
        elif fmt == 'zip':
            with zipfile.ZipFile(output_path, 'r') as zipf:
                bad_file = zipf.testzip()
                if bad_file is not None:
                    print("  Warning: Corrupted file in archive: {0}".format(bad_file),
                          file=sys.stderr)
                    return False
                entries = zipf.namelist()
                print("  Archive contains {0} entries.".format(len(entries)))
            return True
        elif fmt == '7z':
            binary = find_7z_binary()
            if binary:
                process = subprocess.Popen(
                    [binary, 't', output_path],
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE
                )
                stdout, stderr = process.communicate()
                if process.returncode == 0:
                    print("  7z archive verification passed.")
                    return True
                else:
                    print("  Warning: 7z archive verification failed.", file=sys.stderr)
                    return False
            else:
                print("  Skipping 7z verification (binary not found).")
                return True
    except Exception as e:
        print("  Warning: Could not verify archive: {0}".format(e), file=sys.stderr)
        return False


def create_backup(directory, fmt, output_dir=None, verify=True):
    """
    Main backup function that creates a compressed archive of the specified directory.

    Args:
        directory: Path to the directory to back up
        fmt: Compression format ('tar.gz', 'tar.bz2', 'zip', '7z')
        output_dir: Directory to store the backup (default: current directory)
        verify: Whether to verify the archive after creation

    Returns:
        Path to the created archive, or None on failure
    """
    # Normalize directory path
    directory = os.path.abspath(os.path.expanduser(directory))

    # Validate
    if not validate_directory(directory):
        return None

    supported_formats = ['tar.gz', 'tar.bz2', 'zip', '7z']
    if fmt not in supported_formats:
        print("Error: Unsupported format '{0}'. Supported formats: {1}".format(
            fmt, ', '.join(supported_formats)), file=sys.stderr)
        return None

    # Determine output directory
    if output_dir is None:
        output_dir = os.getcwd()
    else:
        output_dir = os.path.abspath(os.path.expanduser(output_dir))
        if not os.path.exists(output_dir):
            try:
                os.makedirs(output_dir)
                print("Created output directory: {0}".format(output_dir))
            except (OSError, IOError) as e:
                print("Error creating output directory: {0}".format(e), file=sys.stderr)
                return None

    # Generate filename
    backup_filename = get_backup_filename(directory, fmt)
    output_path = os.path.join(output_dir, backup_filename)

    # Check if output file already exists
    if os.path.exists(output_path):
        print("Warning: Output file already exists: {0}".format(output_path))
        print("A new filename will be generated.")
        # Append a counter
        counter = 1
        base, ext_part = output_path, ''
        for ext in ['.tar.gz', '.tar.bz2', '.zip', '.7z']:
            if output_path.endswith(ext):
                base = output_path[:-len(ext)]
                ext_part = ext
                break
        while os.path.exists(output_path):
            output_path = "{0}_{1}{2}".format(base, counter, ext_part)
            counter += 1

    # Print backup info
    dir_size = get_directory_size(directory)
    file_count = count_files(directory)
    print("=" * 60)
    print("Backup Configuration:")
    print("  Source:      {0}".format(directory))
    print("  Format:      {0}".format(fmt))
    print("  Output:      {0}".format(output_path))
    print("  Dir size:    {0}".format(format_size(dir_size)))
    print("  File count:  {0}".format(file_count))
    print("=" * 60)

    # Create the archive
    creators = {
        'tar.gz': create_tar_gz,
        'tar.bz2': create_tar_bz2,
        'zip': create_zip,
        '7z': create_7z,
    }

    creator = creators[fmt]
    success = creator(directory, output_path)

    if not success:
        # Clean up partial file
        if os.path.exists(output_path):
            try:
                os.remove(output_path)
            except (OSError, IOError):
                pass
        print("Backup FAILED.", file=sys.stderr)
        return None

    # Verify if requested
    if verify:
        if not verify_archive(output_path, fmt):
            print("Warning: Archive verification had issues.", file=sys.stderr)

    # Print results
    archive_size = os.path.getsize(output_path)
    if dir_size > 0:
        ratio = (1.0 - float(archive_size) / float(dir_size)) * 100.0
    else:
        ratio = 0.0

    print("=" * 60)
    print("Backup completed successfully!")
    print("  Archive:     {0}".format(output_path))
    print("  Archive size: {0}".format(format_size(archive_size)))
    print("  Compression:  {0:.1f}% reduction".format(ratio))
    print("=" * 60)

    return output_path


def parse_args_manual():
    """Manual argument parsing for systems without argparse (Python < 2.7)."""
    directory = None
    fmt = 'tar.gz'
